export interface GlossaryTerm {
  term: string
  slug: string
  definition: string
  relatedTerms?: string[]
  relatedPage?: string
  category: 'astrology' | 'tarot' | 'general'
}

const glossary: GlossaryTerm[] = [
  // === A ===
  { term: 'Archetype', slug: 'archetype', definition: 'A universal symbol or pattern recognized across cultures and mythologies. In tarot, each card embodies an archetype — such as The Fool representing new beginnings or The Mother expressed through The Empress. Archetypes tap into the collective unconscious, which is why tarot imagery resonates so deeply across different traditions.', relatedTerms: ['Major Arcana', 'Significator'], category: 'general' },
  { term: 'Ascendant', slug: 'ascendant', definition: 'The zodiac sign rising on the eastern horizon at the exact moment of your birth, also known as your Rising Sign. The Ascendant shapes your outward personality, physical appearance, and first impressions. It is considered one of the "Big Three" in astrology alongside your Sun and Moon signs.', relatedTerms: ['Rising Sign', 'Birth Chart', 'Natal Chart'], category: 'astrology' },
  { term: 'Aspect', slug: 'aspect', definition: 'A geometric angle formed between two planets in a birth chart, measured in degrees along the ecliptic. Major aspects include conjunctions (0 degrees), sextiles (60 degrees), squares (90 degrees), trines (120 degrees), and oppositions (180 degrees). Aspects describe how planetary energies interact — harmoniously, tensely, or dynamically.', relatedTerms: ['Conjunction', 'Sextile', 'Square', 'Trine', 'Opposition', 'Orb'], category: 'astrology' },
  { term: 'Angular House', slug: 'angular-house', definition: 'The four most powerful houses in a birth chart: the 1st, 4th, 7th, and 10th houses. They correspond to the four angles — Ascendant, IC, Descendant, and MC. Planets placed in angular houses have the strongest influence on a person\'s life, driving action, identity, and public role.', relatedTerms: ['Ascendant', 'IC (Imum Coeli)', 'MC (Midheaven)', 'Succedent House', 'Cadent House'], category: 'astrology' },
  { term: 'Air Signs', slug: 'air-signs', definition: 'The three zodiac signs associated with the element of Air: Gemini, Libra, and Aquarius. Air signs are characterized by intellectualism, communication, social connection, and abstract thinking. They process the world through ideas and relationships rather than emotion or physical sensation.', relatedTerms: ['Modality', 'Polarity'], category: 'astrology' },
  // === B ===
  { term: 'Benefic', slug: 'benefic', definition: 'A planet considered to bring positive, supportive, or fortunate energy. In traditional astrology, Jupiter is the Greater Benefic and Venus is the Lesser Benefic. Benefic planets in prominent chart positions are associated with ease, opportunity, and grace in the areas of life they influence.', relatedTerms: ['Malefic', 'Dignities', 'Domicile'], category: 'astrology' },
  { term: 'Birth Chart', slug: 'birth-chart', definition: 'A map of the sky at the exact moment and location of your birth, showing the positions of the Sun, Moon, planets, and other celestial points across the twelve zodiac signs and houses. Also called a natal chart, it is the foundational document of personal astrology and serves as a blueprint of your personality, strengths, challenges, and life themes.', relatedTerms: ['Natal Chart', 'Ascendant', 'Houses'], relatedPage: '/guides/how-astrology-readings-work', category: 'astrology' },
  { term: 'Bi-Quintile', slug: 'bi-quintile', definition: 'A minor aspect of 144 degrees between two planets, associated with creative talent and unique abilities. Like the quintile, the bi-quintile suggests an innate gift or specialized skill that sets a person apart. It is often found in the charts of artists, innovators, and visionaries.', relatedTerms: ['Aspect', 'Quintile'], category: 'astrology' },
  // === C ===
  { term: 'Cadent House', slug: 'cadent-house', definition: 'The 3rd, 6th, 9th, and 12th houses in a birth chart. Cadent houses are associated with learning, adaptation, and mental activity. Planets in cadent houses express their energy more subtly and internally compared to angular or succedent houses.', relatedTerms: ['Angular House', 'Succedent House', 'Houses'], category: 'astrology' },
  { term: 'Cardinal Sign', slug: 'cardinal-sign', definition: 'The four zodiac signs that initiate each season: Aries (spring), Cancer (summer), Libra (autumn), and Capricorn (winter). Cardinal signs are leaders, starters, and pioneers. They are driven to take action and launch new ventures, though they may struggle with follow-through.', relatedTerms: ['Fixed Sign', 'Mutable Sign', 'Modality'], category: 'astrology' },
  { term: 'Cazimi', slug: 'cazimi', definition: 'A planet that is within 17 minutes of arc of an exact conjunction with the Sun. In traditional astrology, a cazimi planet is considered to be "in the heart of the Sun" and exceptionally powerful — purified and strengthened by its closeness to the solar center. This is the opposite of combust, where proximity to the Sun weakens a planet.', relatedTerms: ['Combust', 'Conjunction'], category: 'astrology' },
  { term: 'Celtic Cross', slug: 'celtic-cross', definition: 'The most widely used tarot spread, consisting of ten cards arranged in a cross and staff pattern. It provides a comprehensive reading covering the present situation, challenges, past influences, future possibilities, inner feelings, external forces, hopes, fears, and outcomes. It is considered an advanced spread due to its complexity and depth.', relatedTerms: ['Tarot Spread', 'Reading'], relatedPage: '/tarot/spreads/celtic-cross', category: 'tarot' },
  { term: 'Chiron', slug: 'chiron', definition: 'A comet-like body orbiting between Saturn and Uranus, known in astrology as the "Wounded Healer." Chiron\'s placement in your chart reveals your deepest wound and, paradoxically, your greatest capacity to heal others. The Chiron return at approximately age 50 marks a significant healing milestone.', relatedTerms: ['Birth Chart', 'Transit'], category: 'astrology' },
  { term: 'Combust', slug: 'combust', definition: 'A planet that is within 8 degrees of the Sun but beyond cazimi range. A combust planet is considered weakened or overwhelmed by the Sun\'s light, making its influence harder to express clearly. The planet\'s qualities may be overshadowed by ego concerns or lack visibility.', relatedTerms: ['Cazimi', 'Conjunction'], category: 'astrology' },
  { term: 'Conjunction', slug: 'conjunction', definition: 'An aspect where two planets occupy the same degree of the zodiac (within an orb of typically 8-10 degrees). Conjunctions blend the energies of both planets, creating intensity and fusion. Whether this is experienced positively or negatively depends on the planets involved and their natures.', relatedTerms: ['Aspect', 'Orb'], category: 'astrology' },
  { term: 'Court Cards', slug: 'court-cards', definition: 'The sixteen personality cards in a tarot deck: four in each suit (typically Page, Knight, Queen, and King). Court cards often represent real people in your life, aspects of your own personality, or the energy you need to embody. They can be the most challenging cards to interpret because their meaning is so context-dependent.', relatedTerms: ['Minor Arcana', 'Wands', 'Cups', 'Swords', 'Pentacles'], category: 'tarot' },
  { term: 'Cups', slug: 'cups', definition: 'One of the four suits of the Minor Arcana, associated with the element of Water. Cups govern emotions, relationships, intuition, creativity, and matters of the heart. The suit ranges from the Ace of Cups (new emotional beginnings) through the Ten of Cups (emotional fulfillment and family harmony).', relatedTerms: ['Minor Arcana', 'Wands', 'Swords', 'Pentacles'], category: 'tarot' },
  { term: 'Cusp', slug: 'cusp', definition: 'The dividing line between two zodiac signs or two houses in a birth chart. Being "born on the cusp" means your birthday falls near the transition between two signs, though technically you are always one sign or the other. House cusps mark where each area of life begins in your chart.', relatedTerms: ['Houses', 'Zodiac'], category: 'astrology' },
  // === D ===
  { term: 'Decan', slug: 'decan', definition: 'A subdivision of each zodiac sign into three 10-degree segments, giving each sign three decans. Each decan is associated with a different planetary ruler and adds nuance to the sign\'s expression. For example, the three decans of Aries are ruled by Mars, the Sun, and Jupiter respectively, giving each a distinct flavor.', relatedTerms: ['Zodiac', 'Ruler'], category: 'astrology' },
  { term: 'Descendant', slug: 'descendant', definition: 'The sign on the cusp of the 7th house, directly opposite the Ascendant. The Descendant represents the qualities you seek in partners and close relationships — often traits you project onto others rather than recognizing in yourself. It is a key point in synastry and relationship astrology.', relatedTerms: ['Ascendant', 'Synastry', 'Angular House'], category: 'astrology' },
  { term: 'Detriment', slug: 'detriment', definition: 'A planet placed in the sign opposite its domicile (home sign). A planet in detriment must work harder to express its energy and may feel uncomfortable or compromised. For example, Mars is in detriment in Libra, where its assertive nature conflicts with Libra\'s desire for harmony and compromise.', relatedTerms: ['Domicile', 'Dignities', 'Exaltation', 'Fall'], category: 'astrology' },
  { term: 'Dignities', slug: 'dignities', definition: 'A system for evaluating how well a planet can express its energy based on its zodiac sign placement. The five essential dignities are domicile (home), exaltation (honored), detriment (challenged), fall (weakened), and peregrine (wandering). Understanding dignities helps astrologers assess the strength and quality of planetary influence.', relatedTerms: ['Domicile', 'Exaltation', 'Detriment', 'Fall'], category: 'astrology' },
  { term: 'Divination', slug: 'divination', definition: 'The practice of seeking knowledge of the future or hidden information through supernatural or intuitive means. Tarot reading is one of the most popular forms of divination, alongside astrology, runes, pendulums, and scrying. The word comes from the Latin "divinare," meaning "to foresee" or "to be inspired by a god."', relatedTerms: ['Reading', 'Intuition', 'Tarot Spread'], category: 'general' },
  { term: 'Domicile', slug: 'domicile', definition: 'The zodiac sign that a planet rules and where it expresses its energy most naturally and powerfully. For example, the Moon\'s domicile is Cancer, Venus rules Taurus and Libra, and Mars rules Aries. A planet in its domicile is considered strong, comfortable, and able to fully express its qualities.', relatedTerms: ['Ruler', 'Dignities', 'Detriment'], category: 'astrology' },
  { term: 'Draw', slug: 'draw', definition: 'The act of selecting cards from a shuffled tarot deck for a reading. Cards can be drawn from the top of the deck, pulled from fanned-out cards, or chosen in whatever manner feels right to the reader. The method of drawing is less important than the intention and focus brought to the moment of selection.', relatedTerms: ['Shuffle', 'Reading', 'Tarot Spread'], category: 'tarot' },
  // === E ===
  { term: 'Earth Signs', slug: 'earth-signs', definition: 'The three zodiac signs associated with the element of Earth: Taurus, Virgo, and Capricorn. Earth signs are practical, grounded, reliable, and focused on the material world. They process life through physical sensation, tangible results, and methodical effort.', relatedTerms: ['Modality', 'Polarity'], category: 'astrology' },
  { term: 'Eclipse', slug: 'eclipse', definition: 'An astronomical event where the Sun, Moon, and Earth align precisely, creating either a solar eclipse (Moon blocks the Sun at a New Moon) or a lunar eclipse (Earth\'s shadow falls on the Moon at a Full Moon). In astrology, eclipses are potent catalysts for change, often triggering significant life events near the degrees they activate.', relatedTerms: ['Lunation', 'North Node', 'South Node'], category: 'astrology' },
  { term: 'Electional Astrology', slug: 'electional-astrology', definition: 'A branch of astrology that uses chart analysis to choose the most auspicious time to begin an activity — such as launching a business, getting married, or signing a contract. By selecting a moment when planetary alignments support your goals, electional astrology aims to give new ventures the best possible cosmic start.', relatedTerms: ['Transit', 'Birth Chart'], category: 'astrology' },
  { term: 'Elemental Dignities', slug: 'elemental-dignities', definition: 'A tarot interpretation method that considers the elemental relationships between cards. Fire and Air are friendly, Water and Earth are friendly, while Fire and Water or Air and Earth weaken each other. Using elemental dignities adds a layer of nuance to multi-card readings by showing how adjacent cards support or undermine one another.', relatedTerms: ['Wands', 'Cups', 'Swords', 'Pentacles'], category: 'tarot' },
  { term: 'Ephemeris', slug: 'ephemeris', definition: 'A table or publication listing the daily positions of the Sun, Moon, and planets in the zodiac. Before astrology software, the ephemeris was the astrologer\'s essential reference for calculating birth charts and tracking planetary movements. Modern digital ephemerides are built into astrology apps and websites.', relatedTerms: ['Transit', 'Birth Chart'], category: 'astrology' },
  { term: 'Exaltation', slug: 'exaltation', definition: 'A zodiac sign where a planet\'s energy is elevated, honored, and especially potent — though not as comfortable as in its domicile. For example, the Sun is exalted in Aries, the Moon in Taurus, and Saturn in Libra. An exalted planet performs at its best, like a guest of honor at a banquet.', relatedTerms: ['Dignities', 'Domicile', 'Fall', 'Detriment'], category: 'astrology' },
  // === F ===
  { term: 'Fall', slug: 'fall', definition: 'The zodiac sign opposite a planet\'s exaltation, where the planet\'s energy is weakened and struggles to express itself effectively. The Sun is in fall in Libra, the Moon in Scorpio, and Saturn in Aries. A planet in fall must work harder and may express its qualities in distorted or underperforming ways.', relatedTerms: ['Exaltation', 'Dignities', 'Detriment', 'Domicile'], category: 'astrology' },
  { term: 'Fire Signs', slug: 'fire-signs', definition: 'The three zodiac signs associated with the element of Fire: Aries, Leo, and Sagittarius. Fire signs are passionate, energetic, bold, and action-oriented. They process life through enthusiasm, inspiration, and creative self-expression, often leading with courage and spontaneity.', relatedTerms: ['Modality', 'Polarity'], category: 'astrology' },
  { term: 'Fixed Sign', slug: 'fixed-sign', definition: 'The four zodiac signs that fall in the middle of each season: Taurus (spring), Leo (summer), Scorpio (autumn), and Aquarius (winter). Fixed signs are determined, persistent, and resistant to change. They provide stability and follow-through but can become stubborn when pushed.', relatedTerms: ['Cardinal Sign', 'Mutable Sign', 'Modality'], category: 'astrology' },
  { term: 'Fool\'s Journey', slug: 'fools-journey', definition: 'A narrative framework that interprets the 22 Major Arcana cards as a sequential story of spiritual development. Beginning with The Fool (innocence and potential) and ending with The World (completion and integration), the journey maps the human experience of growth through challenge, transformation, and ultimately wisdom.', relatedTerms: ['Major Arcana', 'Archetype'], category: 'tarot' },
  // === G ===
  { term: 'Grand Cross', slug: 'grand-cross', definition: 'A rare chart pattern formed when four planets create two oppositions that cross each other, forming a square at each corner. The Grand Cross creates intense tension and drive across four areas of life simultaneously. While challenging, it can produce extraordinary determination and the ability to manage complex, competing demands.', relatedTerms: ['Square', 'Opposition', 'T-Square'], category: 'astrology' },
  { term: 'Grand Trine', slug: 'grand-trine', definition: 'A harmonious chart pattern formed when three planets are each approximately 120 degrees apart, creating an equilateral triangle in the chart. Grand Trines indicate natural talent and ease in the element involved (Fire, Earth, Air, or Water) but can also create complacency because things come too easily.', relatedTerms: ['Trine', 'Aspect'], category: 'astrology' },
  // === H ===
  { term: 'Houses', slug: 'houses', definition: 'The twelve divisions of a birth chart that represent different areas of life — from identity (1st house) to spirituality (12th house). Each house is associated with specific themes: relationships, career, home, communication, creativity, health, and more. The planets in each house show where their energy is most active.', relatedTerms: ['Angular House', 'Succedent House', 'Cadent House', 'Birth Chart'], category: 'astrology' },
  { term: 'Horary Astrology', slug: 'horary-astrology', definition: 'A branch of astrology that answers specific questions by casting a chart for the moment the question is asked. Rather than using a birth chart, horary uses the "birth" of the question itself. It is remarkably precise for yes/no questions and finding lost objects, with a structured set of rules for interpretation.', relatedTerms: ['Electional Astrology', 'Birth Chart'], category: 'astrology' },
  // === I ===
  { term: 'IC (Imum Coeli)', slug: 'ic-imum-coeli', definition: 'The lowest point of the birth chart, located at the cusp of the 4th house. The IC represents your roots, home, family, private self, and emotional foundation. It is the most intimate point in the chart — the part of you that only those closest to you ever see. It opposes the MC (Midheaven) at the top of the chart.', relatedTerms: ['MC (Midheaven)', 'Angular House', 'Houses'], category: 'astrology' },
  { term: 'Ingress', slug: 'ingress', definition: 'The moment a planet moves from one zodiac sign into the next. Ingresses mark significant shifts in energy, especially when slow-moving outer planets change signs. The Aries Ingress — when the Sun enters Aries at the spring equinox — is traditionally used to forecast the year ahead in mundane astrology.', relatedTerms: ['Transit', 'Zodiac'], category: 'astrology' },
  { term: 'Intercepted Sign', slug: 'intercepted-sign', definition: 'A zodiac sign that is fully contained within a house without appearing on any house cusp. Intercepted signs indicate energies that are present but harder to access or express. They often represent qualities that were suppressed or underdeveloped in childhood and require conscious effort to integrate.', relatedTerms: ['Cusp', 'Houses'], category: 'astrology' },
  { term: 'Intuition', slug: 'intuition', definition: 'The ability to understand something immediately without conscious reasoning. In tarot and astrology, intuition is the bridge between technical knowledge and personal insight. While learning card meanings and planetary dignities provides the foundation, it is intuition that transforms information into meaningful, personalized guidance.', relatedTerms: ['Reading', 'Divination'], category: 'general' },
  // === J ===
  { term: 'Jupiter', slug: 'jupiter', definition: 'The largest planet in our solar system and the Greater Benefic in astrology. Jupiter represents expansion, abundance, wisdom, optimism, higher education, travel, and philosophical understanding. Its sign and house placement show where you experience growth and good fortune. Jupiter takes about 12 years to orbit the zodiac.', relatedTerms: ['Benefic', 'Transit'], category: 'astrology' },
  { term: 'Jupiter Return', slug: 'jupiter-return', definition: 'An astrological event occurring approximately every 12 years when Jupiter returns to the exact position it held at your birth. Jupiter returns mark periods of growth, opportunity, and renewed optimism. The first return at age 12, the second around 24, and the third near 36 each mark significant expansion phases.', relatedTerms: ['Jupiter', 'Transit', 'Saturn Return'], category: 'astrology' },
  // === K ===
  { term: 'Kite', slug: 'kite', definition: 'A chart pattern formed when a Grand Trine has one planet that also forms an opposition, creating two sextiles to the other trine planets. The Kite takes the natural talent of the Grand Trine and adds a focal point of tension and drive, channeling the easy-flowing energy toward a specific purpose or achievement.', relatedTerms: ['Grand Trine', 'Opposition', 'Sextile'], category: 'astrology' },
  // === L ===
  { term: 'Lilith', slug: 'lilith', definition: 'In astrology, Black Moon Lilith is a mathematical point representing the lunar apogee — the Moon\'s farthest point from Earth. Lilith symbolizes the wild, untamed, and repressed aspects of the feminine psyche. Its chart placement reveals where you may experience rejection, rage, empowerment, and the reclaiming of suppressed desires.', relatedTerms: ['Birth Chart', 'North Node'], category: 'astrology' },
  { term: 'Lot of Fortune', slug: 'lot-of-fortune', definition: 'An Arabic Part (also called Part of Fortune) calculated from the positions of the Sun, Moon, and Ascendant. It indicates an area of life where natural luck, material well-being, and physical vitality are strongest. In Hellenistic astrology, the Lot of Fortune was considered nearly as important as the luminaries.', relatedTerms: ['Part of Fortune', 'Birth Chart', 'Ascendant'], category: 'astrology' },
  { term: 'Lunation', slug: 'lunation', definition: 'A complete lunar cycle from one New Moon to the next, lasting approximately 29.5 days. Lunations are fundamental timing mechanisms in both astrology and tarot practice. Each lunation carries the flavor of its zodiac sign and forms aspects to your birth chart, creating monthly themes of initiation, growth, and release.', relatedTerms: ['Eclipse', 'New Moon', 'Full Moon'], category: 'astrology' },
  // === M ===
  { term: 'Major Arcana', slug: 'major-arcana', definition: 'The 22 trump cards of the tarot deck, numbered 0 (The Fool) through 21 (The World). Major Arcana cards represent major life themes, spiritual lessons, and archetypal forces. When they appear in a reading, they signal that significant, karmic, or life-changing energies are at play — forces that go beyond everyday circumstances.', relatedTerms: ['Minor Arcana', 'Fool\'s Journey', 'Archetype'], category: 'tarot' },
  { term: 'Malefic', slug: 'malefic', definition: 'A planet considered to bring challenging, restrictive, or difficult energy. In traditional astrology, Saturn is the Greater Malefic and Mars is the Lesser Malefic. Modern astrology views malefic planets not as "bad" but as teachers that promote growth through adversity, discipline, and confrontation.', relatedTerms: ['Benefic', 'Saturn', 'Mars'], category: 'astrology' },
  { term: 'Mars', slug: 'mars', definition: 'The fourth planet from the Sun and the Lesser Malefic in traditional astrology. Mars represents drive, aggression, courage, physical energy, sexuality, and the will to act. Its chart placement shows how you assert yourself, handle conflict, and pursue what you want. Mars takes about two years to orbit the zodiac.', relatedTerms: ['Malefic', 'Ruler'], category: 'astrology' },
  { term: 'MC (Midheaven)', slug: 'mc-midheaven', definition: 'The highest point of the birth chart, located at the cusp of the 10th house. The MC represents your public image, career path, reputation, and highest aspirations. It is what you are known for in the world and the legacy you build. The MC opposes the IC at the bottom of the chart.', relatedTerms: ['IC (Imum Coeli)', 'Angular House', 'Houses'], category: 'astrology' },
  { term: 'Mercury', slug: 'mercury', definition: 'The closest planet to the Sun and the ruler of communication, intellect, travel, and commerce in astrology. Mercury governs how you think, speak, learn, and process information. Its sign placement colors your communication style, while its house placement shows where mental activity is most focused.', relatedTerms: ['Retrograde', 'Ruler'], relatedPage: '/guides/mercury-retrograde', category: 'astrology' },
  { term: 'Mercury Retrograde', slug: 'mercury-retrograde', definition: 'A period approximately three times per year when Mercury appears to move backward through the zodiac from Earth\'s perspective. Associated with communication breakdowns, technology glitches, travel delays, and misunderstandings. It is actually an excellent time for reflection, revision, and reconnecting with the past.', relatedTerms: ['Retrograde', 'Mercury', 'Transit'], relatedPage: '/guides/mercury-retrograde', category: 'astrology' },
  { term: 'Minor Arcana', slug: 'minor-arcana', definition: 'The 56 cards of the tarot deck divided into four suits: Wands (Fire), Cups (Water), Swords (Air), and Pentacles (Earth). Each suit contains cards numbered Ace through Ten plus four Court Cards. Minor Arcana cards represent everyday events, practical matters, and the daily navigation of life.', relatedTerms: ['Major Arcana', 'Wands', 'Cups', 'Swords', 'Pentacles', 'Court Cards', 'Pip Cards'], category: 'tarot' },
  { term: 'Modality', slug: 'modality', definition: 'One of three qualities assigned to zodiac signs based on their position in the season: Cardinal (initiating), Fixed (sustaining), and Mutable (adapting). Each element has one sign in each modality. The modality of a sign reveals its fundamental approach to life — whether it starts things, maintains them, or transforms them.', relatedTerms: ['Cardinal Sign', 'Fixed Sign', 'Mutable Sign'], category: 'astrology' },
  { term: 'Moon', slug: 'moon', definition: 'Earth\'s natural satellite and one of the most important bodies in astrology. The Moon represents your emotional nature, instincts, subconscious patterns, nurturing style, and what you need to feel safe. It changes signs approximately every 2.5 days, making the Moon sign one of the most personal placements in a chart.', relatedTerms: ['Lunation', 'Eclipse', 'Birth Chart'], category: 'astrology' },
  { term: 'Moon Phases', slug: 'moon-phases', definition: 'The eight distinct stages of the Moon\'s monthly cycle: New Moon, Waxing Crescent, First Quarter, Waxing Gibbous, Full Moon, Waning Gibbous, Last Quarter, and Waning Crescent. Each phase carries specific energy for manifestation work, tarot practice, and personal development.', relatedTerms: ['Lunation', 'Moon'], category: 'astrology' },
  { term: 'Mundane Astrology', slug: 'mundane-astrology', definition: 'The branch of astrology that studies world events, nations, politics, weather, and collective trends rather than individual charts. Mundane astrologers analyze eclipses, planetary conjunctions, and ingress charts to forecast global shifts. It is one of the oldest forms of astrological practice.', relatedTerms: ['Eclipse', 'Ingress'], category: 'astrology' },
  { term: 'Mutable Sign', slug: 'mutable-sign', definition: 'The four zodiac signs that close each season: Gemini (spring), Virgo (summer), Sagittarius (autumn), and Pisces (winter). Mutable signs are adaptable, flexible, and skilled at transitioning between phases. They are communicators and connectors who thrive on variety but may struggle with commitment.', relatedTerms: ['Cardinal Sign', 'Fixed Sign', 'Modality'], category: 'astrology' },
  { term: 'Mystic Rectangle', slug: 'mystic-rectangle', definition: 'A rare aspect pattern formed by two oppositions, two trines, and two sextiles creating a rectangle in the birth chart. The Mystic Rectangle combines tension (oppositions) with harmony (trines and sextiles), creating a dynamic but ultimately productive pattern. People with this pattern often have a talent for balancing opposing forces.', relatedTerms: ['Opposition', 'Trine', 'Sextile', 'Aspect'], category: 'astrology' },
  // === N ===
  { term: 'Nadir', slug: 'nadir', definition: 'The point directly below the observer, opposite the zenith. In astrology, the nadir corresponds to the IC (Imum Coeli) — the bottom of the chart representing home, roots, and the private self. It is the most hidden and personal point in the horoscope, associated with ancestral heritage and emotional foundations.', relatedTerms: ['IC (Imum Coeli)', 'Zenith'], category: 'astrology' },
  { term: 'Natal Chart', slug: 'natal-chart', definition: 'Another term for birth chart — a map of the celestial positions at the exact time, date, and place of your birth. The natal chart is the foundational tool of personal astrology, revealing your personality traits, life themes, strengths, challenges, and soul purpose through the language of planets, signs, and houses.', relatedTerms: ['Birth Chart', 'Ascendant', 'Houses'], relatedPage: '/guides/how-astrology-readings-work', category: 'astrology' },
  { term: 'Neptune', slug: 'neptune', definition: 'The eighth planet from the Sun, ruling dreams, illusions, spirituality, compassion, and transcendence. Neptune dissolves boundaries and invites connection with the divine, but can also bring confusion, deception, and escapism. As a generational planet, it spends about 14 years in each sign.', relatedTerms: ['Outer Planets', 'Transit'], category: 'astrology' },
  { term: 'North Node', slug: 'north-node', definition: 'A mathematical point where the Moon\'s orbit crosses the ecliptic from south to north. In astrology, the North Node represents your soul\'s growth direction — the qualities, experiences, and life areas you are meant to develop in this lifetime. It often points toward uncomfortable but rewarding territory that pushes you beyond your comfort zone.', relatedTerms: ['South Node', 'Eclipse', 'Birth Chart'], category: 'astrology' },
  { term: 'Numerology', slug: 'numerology', definition: 'The study of the mystical significance of numbers and their influence on human life. In tarot, numerology adds depth to card interpretation — Aces represent beginnings, Twos duality, Threes creation, and so on. Each numbered card across the four suits shares thematic resonance with its number.', relatedTerms: ['Major Arcana', 'Pip Cards'], category: 'general' },
  // === O ===
  { term: 'Opposition', slug: 'opposition', definition: 'An aspect of 180 degrees between two planets, placing them on opposite sides of the zodiac. Oppositions create tension, awareness, and the need to balance two competing energies. They often manifest through relationships, as the opposing energy is projected onto others. Oppositions demand integration rather than choosing one side.', relatedTerms: ['Aspect', 'Conjunction', 'Square'], category: 'astrology' },
  { term: 'Orb', slug: 'orb', definition: 'The degree of deviation from an exact aspect that is still considered active. A conjunction with an orb of 8 degrees means planets within 8 degrees of exact alignment are still considered conjunct. Tighter orbs produce stronger effects. Different astrologers use different orb sizes, typically ranging from 1 to 10 degrees depending on the aspect and planets involved.', relatedTerms: ['Aspect', 'Conjunction'], category: 'astrology' },
  { term: 'Outer Planets', slug: 'outer-planets', definition: 'Uranus, Neptune, and Pluto — the three planets beyond Saturn that were discovered in modern times. They move slowly through the zodiac and represent generational and collective forces: revolution (Uranus), transcendence (Neptune), and transformation (Pluto). Their influence on individuals is strongest through house placement and aspects to personal planets.', relatedTerms: ['Uranus', 'Neptune', 'Pluto', 'Transit'], category: 'astrology' },
  // === P ===
  { term: 'Part of Fortune', slug: 'part-of-fortune', definition: 'An Arabic Part calculated from the Sun, Moon, and Ascendant positions that indicates where material fortune, physical well-being, and worldly success flow most naturally. Its house and sign placement show the area of life where you are most likely to find prosperity and contentment through aligned effort.', relatedTerms: ['Lot of Fortune', 'Birth Chart'], category: 'astrology' },
  { term: 'Pentacles', slug: 'pentacles', definition: 'One of the four suits of the Minor Arcana, associated with the element of Earth. Pentacles govern material matters: money, career, health, home, and physical security. The suit ranges from the Ace of Pentacles (new financial opportunity) through the Ten of Pentacles (generational wealth and family legacy). Also called Coins or Discs in some decks.', relatedTerms: ['Minor Arcana', 'Wands', 'Cups', 'Swords'], category: 'tarot' },
  { term: 'Pip Cards', slug: 'pip-cards', definition: 'The numbered cards (Ace through Ten) of each suit in the Minor Arcana, as distinguished from the Court Cards. In older tarot traditions, pip cards showed only the suit symbols without illustrated scenes. Modern decks like the Rider-Waite-Smith depict narrative scenes on each pip card, making them easier to read intuitively.', relatedTerms: ['Minor Arcana', 'Court Cards', 'Numerology'], category: 'tarot' },
  { term: 'Pluto', slug: 'pluto', definition: 'The dwarf planet representing profound transformation, power, death and rebirth, the shadow self, and collective upheaval. Pluto destroys what is no longer authentic to make way for deep regeneration. It spends 12 to 31 years in each sign, marking generational shifts in what society must transform.', relatedTerms: ['Outer Planets', 'Transit'], category: 'astrology' },
  { term: 'Polarity', slug: 'polarity', definition: 'The division of the twelve zodiac signs into two groups: positive/masculine (Fire and Air signs) and negative/feminine (Earth and Water signs). Polarity describes the fundamental orientation of energy — outward and active (positive) or inward and receptive (negative). Each sign is paired with its opposite for complementary balance.', relatedTerms: ['Zodiac', 'Modality'], category: 'astrology' },
  { term: 'Prenatal Eclipse', slug: 'prenatal-eclipse', definition: 'The last solar eclipse that occurred before your birth. In traditional astrology, the prenatal eclipse degree is a sensitive point in your chart that can be activated by transits and progressions throughout your life. Some astrologers consider it a karmic indicator related to your soul\'s purpose and past-life patterns.', relatedTerms: ['Eclipse', 'Birth Chart'], category: 'astrology' },
  { term: 'Progressed Chart', slug: 'progressed-chart', definition: 'A forecasting technique that advances your birth chart by one day for each year of life (secondary progressions). If you are 30 years old, your progressed chart reflects the sky 30 days after your birth. Progressed charts reveal inner psychological evolution and major life transitions, particularly through the progressed Moon\'s sign changes.', relatedTerms: ['Birth Chart', 'Transit'], category: 'astrology' },
  // === Q ===
  { term: 'Querent', slug: 'querent', definition: 'The person asking the question in a tarot reading. Whether reading for yourself or receiving a reading from another person, the querent is the one whose question and energy direct the reading. A clear, focused querent with a specific question generally receives a clearer reading.', relatedTerms: ['Reading', 'Significator'], category: 'tarot' },
  { term: 'Quincunx', slug: 'quincunx', definition: 'An aspect of 150 degrees between two planets, also called an inconjunct. The quincunx connects signs that share no element, modality, or polarity, creating a fundamental mismatch that requires constant adjustment. It produces a nagging sense that something needs fixing — an itch that cannot quite be scratched — and demands creative adaptation.', relatedTerms: ['Aspect', 'Yod'], category: 'astrology' },
  { term: 'Quintile', slug: 'quintile', definition: 'A minor aspect of 72 degrees associated with creativity, talent, and unique gifts. Quintiles indicate areas where a person possesses a special creative or intellectual ability that sets them apart. They are often overlooked in chart readings but can reveal hidden talents and unconventional strengths.', relatedTerms: ['Aspect', 'Bi-Quintile'], category: 'astrology' },
  // === R ===
  { term: 'Reading', slug: 'reading', definition: 'A session in which tarot cards or an astrological chart are interpreted to provide insight, guidance, or answers to questions. Readings can be done for yourself or by a professional reader. A good reading combines technical knowledge with intuitive insight and delivers information that is both meaningful and actionable.', relatedTerms: ['Querent', 'Tarot Spread', 'Divination'], relatedPage: '/guides/how-astrology-readings-work', category: 'general' },
  { term: 'Reception', slug: 'reception', definition: 'A condition in which two planets are in each other\'s signs of dignity — for example, Mars in Libra (Venus\'s sign) and Venus in Aries (Mars\'s sign). Mutual reception creates a supportive link between the planets, as each "hosts" the other. It is like a diplomatic exchange that allows both planets to function more effectively despite challenging placements.', relatedTerms: ['Dignities', 'Domicile', 'Ruler'], category: 'astrology' },
  { term: 'Retrograde', slug: 'retrograde', definition: 'The apparent backward motion of a planet through the zodiac as seen from Earth. No planet actually moves backward — it is an optical illusion caused by orbital speeds. In astrology, retrograde periods signal times to review, revise, and reflect on the themes governed by that planet. Mercury retrogrades are the most widely discussed, but all planets except the Sun and Moon go retrograde.', relatedTerms: ['Mercury Retrograde', 'Transit'], relatedPage: '/guides/mercury-retrograde', category: 'astrology' },
  { term: 'Reversed', slug: 'reversed', definition: 'A tarot card that appears upside-down when drawn. Reversed cards can indicate blocked energy, internalized qualities, delays, resistance, or the shadow side of the upright meaning. Not all readers use reversals — some prefer to read all cards upright and find nuance through position and surrounding cards instead.', relatedTerms: ['Upright', 'Reading'], category: 'tarot' },
  { term: 'Rising Sign', slug: 'rising-sign', definition: 'Another name for the Ascendant — the zodiac sign that was rising over the eastern horizon at your exact time of birth. Your Rising Sign governs first impressions, physical appearance, and the mask you wear in public. It is why people born under the same Sun sign can seem so different from one another.', relatedTerms: ['Ascendant', 'Birth Chart'], category: 'astrology' },
  { term: 'Ruler', slug: 'ruler', definition: 'The planet that has natural affinity with and governance over a zodiac sign. Each sign has a traditional ruler and, in modern astrology, some signs have co-rulers. For example, Scorpio is traditionally ruled by Mars and co-ruled by Pluto. The ruler of a house\'s sign is called the house ruler, and its placement reveals additional information about that life area.', relatedTerms: ['Domicile', 'Dignities'], category: 'astrology' },
  // === S ===
  { term: 'Saturn', slug: 'saturn', definition: 'The sixth planet from the Sun, known as the Greater Malefic in traditional astrology and the Lord of Time and Karma. Saturn represents discipline, responsibility, structure, limitations, maturity, and hard-won achievement. Its chart placement shows where you face your greatest challenges and, through perseverance, build your most enduring accomplishments.', relatedTerms: ['Malefic', 'Saturn Return'], relatedPage: '/guides/saturn-return', category: 'astrology' },
  { term: 'Saturn Return', slug: 'saturn-return', definition: 'A major astrological transit occurring approximately every 29.5 years when Saturn returns to the exact zodiac position it held at your birth. The first Saturn Return (ages 27-30) marks the transition from youth to true adulthood. The second (ages 56-60) brings a re-evaluation of achievements and legacy. It is often experienced as a period of significant life restructuring.', relatedTerms: ['Saturn', 'Transit'], relatedPage: '/guides/saturn-return', category: 'astrology' },
  { term: 'Sect', slug: 'sect', definition: 'A traditional astrological concept dividing planets into day (diurnal) and night (nocturnal) teams. In a day chart (Sun above the horizon), the Sun, Jupiter, and Saturn are the sect planets; in a night chart, the Moon, Venus, and Mars lead. A planet in its preferred sect expresses its energy more constructively.', relatedTerms: ['Benefic', 'Malefic', 'Birth Chart'], category: 'astrology' },
  { term: 'Semi-Sextile', slug: 'semi-sextile', definition: 'A minor aspect of 30 degrees between two planets. The semi-sextile connects adjacent signs that have little in common, creating a subtle irritation or low-level awareness that prompts small adjustments. It is often overlooked but can indicate areas where minor fine-tuning yields meaningful results.', relatedTerms: ['Aspect', 'Sextile'], category: 'astrology' },
  { term: 'Semi-Square', slug: 'semi-square', definition: 'A minor aspect of 45 degrees between two planets, representing a lesser version of the square\'s friction and tension. Semi-squares create internal irritation, restlessness, and the motivation to make changes. They are like small splinters — easy to ignore but persistent until addressed.', relatedTerms: ['Aspect', 'Square'], category: 'astrology' },
  { term: 'Sextile', slug: 'sextile', definition: 'A harmonious aspect of 60 degrees between two planets. Sextiles represent opportunities, talents, and natural cooperation between the energies involved. Unlike trines, which flow automatically, sextiles require a small effort to activate — they are doors that open when you knock rather than pathways that carry you forward on their own.', relatedTerms: ['Aspect', 'Trine'], category: 'astrology' },
  { term: 'Shadow Period', slug: 'shadow-period', definition: 'The period before and after a planet\'s retrograde station when it moves through the degrees it will later retrace. Mercury\'s shadow period begins about two weeks before retrograde and ends two weeks after it goes direct. Events and themes from the shadow period often connect to the retrograde itself, making it part of the full retrograde cycle.', relatedTerms: ['Retrograde', 'Mercury Retrograde'], relatedPage: '/guides/mercury-retrograde', category: 'astrology' },
  { term: 'Shuffle', slug: 'shuffle', definition: 'The act of mixing tarot cards before a reading. Shuffling is both a practical step and a meditative practice — it is the time when you focus your intention, connect with the deck, and allow the cards to arrange themselves. There is no single correct way to shuffle; overhand, riffle, and spreading cards on a table are all valid methods.', relatedTerms: ['Draw', 'Reading'], category: 'tarot' },
  { term: 'Significator', slug: 'significator', definition: 'A tarot card deliberately chosen to represent the querent or the subject of the reading. Some readers select a Court Card based on the querent\'s age, gender, or zodiac sign. Others let the deck choose by drawing a card. Not all readers use significators — many prefer to let every card be available for the reading itself.', relatedTerms: ['Querent', 'Court Cards'], category: 'tarot' },
  { term: 'Solar Return', slug: 'solar-return', definition: 'An astrological chart cast for the exact moment the Sun returns to its natal position each year — your "cosmic birthday." The Solar Return chart provides a forecast for the year ahead, highlighting themes, opportunities, and challenges from birthday to birthday. It is one of the most popular predictive techniques in modern astrology.', relatedTerms: ['Transit', 'Birth Chart', 'Sun'], category: 'astrology' },
  { term: 'South Node', slug: 'south-node', definition: 'The point opposite the North Node, representing your past-life skills, comfort zone, and default patterns. The South Node shows what comes naturally to you — talents and tendencies carried from previous experience. While these gifts are valuable, over-relying on South Node patterns can prevent the growth your North Node demands.', relatedTerms: ['North Node', 'Eclipse', 'Birth Chart'], category: 'astrology' },
  { term: 'Square', slug: 'square', definition: 'An aspect of 90 degrees between two planets, creating dynamic tension, friction, and the motivation to act. Squares are the engine of growth in astrology — they are uncomfortable but productive. They force you to confront challenges and make choices rather than drifting passively. The most accomplished charts often have strong squares.', relatedTerms: ['Aspect', 'Opposition', 'T-Square'], category: 'astrology' },
  { term: 'Stellium', slug: 'stellium', definition: 'A cluster of three or more planets in the same zodiac sign or house. A stellium concentrates enormous energy in one area of life, creating both exceptional talent and potential imbalance. People with stelliums tend to be intensely focused on the themes of the occupied sign or house, sometimes to the neglect of other areas.', relatedTerms: ['Birth Chart', 'Houses', 'Conjunction'], category: 'astrology' },
  { term: 'Succedent House', slug: 'succedent-house', definition: 'The 2nd, 5th, 8th, and 11th houses in a birth chart. Succedent houses follow the angular houses and are associated with resources, values, and stabilization. Planets in succedent houses have moderate strength and often relate to how you accumulate, share, and enjoy the things that sustain you.', relatedTerms: ['Angular House', 'Cadent House', 'Houses'], category: 'astrology' },
  { term: 'Sun', slug: 'sun', definition: 'The central star of our solar system and the most fundamental placement in astrology. Your Sun sign represents your core identity, ego, willpower, vitality, and life purpose. It is the essence of who you are becoming throughout your lifetime. The Sun spends approximately one month in each zodiac sign.', relatedTerms: ['Birth Chart', 'Zodiac', 'Solar Return'], category: 'astrology' },
  { term: 'Sun Sign', slug: 'sun-sign', definition: 'The zodiac sign the Sun was in at the time of your birth. This is the sign most people know and the basis for newspaper horoscopes. While your Sun sign is significant, it is only one piece of a much larger birth chart that includes Moon sign, Rising sign, and the positions of all other planets.', relatedTerms: ['Sun', 'Zodiac', 'Birth Chart'], category: 'astrology' },
  { term: 'Swords', slug: 'swords', definition: 'One of the four suits of the Minor Arcana, associated with the element of Air. Swords govern the mind, intellect, communication, conflict, truth, and decision-making. The suit is often perceived as the most challenging because it deals with mental struggles, but Swords also bring clarity, justice, and the power of discernment.', relatedTerms: ['Minor Arcana', 'Wands', 'Cups', 'Pentacles'], category: 'tarot' },
  { term: 'Synastry', slug: 'synastry', definition: 'The astrological technique of comparing two birth charts to analyze relationship compatibility and dynamics. By overlaying the charts, an astrologer can see where two people\'s planets interact — forming harmonious or challenging aspects. Synastry reveals the strengths, tensions, and growth potential in any relationship.', relatedTerms: ['Birth Chart', 'Aspect', 'Composite Chart'], relatedPage: '/guides/how-astrology-readings-work', category: 'astrology' },
  // === T ===
  { term: 'T-Square', slug: 't-square', definition: 'An aspect pattern formed by two planets in opposition with a third planet squaring both, creating a T shape. The T-Square generates persistent tension and drive focused on the planet at the apex. It is one of the most motivating patterns in astrology, pushing people to take action and achieve despite ongoing challenges.', relatedTerms: ['Square', 'Opposition', 'Grand Cross'], category: 'astrology' },
  { term: 'Tarot Spread', slug: 'tarot-spread', definition: 'A predetermined layout of card positions, each assigned a specific meaning, used to structure a tarot reading. Spreads range from a single card to elaborate multi-card arrangements like the Celtic Cross. The spread provides a narrative framework that transforms individual card meanings into a cohesive story.', relatedTerms: ['Celtic Cross', 'Reading', 'Draw'], relatedPage: '/tarot/spreads', category: 'tarot' },
  { term: 'Transit', slug: 'transit', definition: 'The current real-time movement of a planet through the zodiac and its relationship to your birth chart. When a transiting planet forms an aspect to a natal planet, it activates that area of your chart and triggers related events or internal shifts. Tracking transits is the primary method for astrological forecasting.', relatedTerms: ['Aspect', 'Birth Chart', 'Retrograde'], category: 'astrology' },
  { term: 'Trine', slug: 'trine', definition: 'A harmonious aspect of 120 degrees between two planets, typically connecting signs of the same element. Trines represent natural talent, ease, and flow — things that come effortlessly. While highly positive, an overabundance of trines without challenging aspects can lead to complacency because there is insufficient friction to motivate growth.', relatedTerms: ['Aspect', 'Sextile', 'Grand Trine'], category: 'astrology' },
  // === U ===
  { term: 'Upright', slug: 'upright', definition: 'A tarot card drawn right-side-up, displaying its standard, full-strength meaning. Upright cards represent the direct expression of the card\'s energy — its most recognizable themes and qualities. When contrasted with reversed cards, upright positions tend to suggest external expression and forward momentum.', relatedTerms: ['Reversed', 'Reading'], category: 'tarot' },
  { term: 'Uranus', slug: 'uranus', definition: 'The seventh planet from the Sun, representing sudden change, rebellion, innovation, freedom, and awakening. Uranus breaks structures and conventions to create space for progress and originality. Its transits can feel disruptive but ultimately liberate. Uranus takes 84 years to orbit the zodiac, spending about 7 years in each sign.', relatedTerms: ['Outer Planets', 'Transit'], category: 'astrology' },
  // === V ===
  { term: 'Venus', slug: 'venus', definition: 'The second planet from the Sun, known as the Lesser Benefic in traditional astrology. Venus governs love, beauty, pleasure, values, money, relationships, and aesthetic sensibility. Your Venus sign shows how you love and what you find attractive, while its house placement reveals where these themes are most active in your life.', relatedTerms: ['Benefic', 'Ruler'], category: 'astrology' },
  { term: 'Vertex', slug: 'vertex', definition: 'A sensitive point in the western hemisphere of the birth chart, often called the "point of fate." The Vertex is associated with fated encounters, destined relationships, and turning points that feel beyond personal control. When transiting or progressed planets activate the Vertex, significant people or events often enter your life unexpectedly.', relatedTerms: ['Birth Chart', 'Transit'], category: 'astrology' },
  { term: 'Void of Course', slug: 'void-of-course', definition: 'A period when the Moon has made its last major aspect to another planet in its current sign and will not make another until it enters the next sign. During void-of-course periods, it is traditionally advised to avoid starting new projects, signing contracts, or making major decisions, as things initiated during these times tend to come to nothing.', relatedTerms: ['Moon', 'Aspect', 'Transit'], category: 'astrology' },
  // === W ===
  { term: 'Wands', slug: 'wands', definition: 'One of the four suits of the Minor Arcana, associated with the element of Fire. Wands govern passion, creativity, ambition, energy, action, and spiritual growth. The suit ranges from the Ace of Wands (creative spark) through the Ten of Wands (burden of responsibility). Also called Rods, Staves, or Batons in some decks.', relatedTerms: ['Minor Arcana', 'Cups', 'Swords', 'Pentacles'], category: 'tarot' },
  { term: 'Water Signs', slug: 'water-signs', definition: 'The three zodiac signs associated with the element of Water: Cancer, Scorpio, and Pisces. Water signs are emotional, intuitive, empathetic, and deeply feeling. They process life through emotion, instinct, and psychic sensitivity, often absorbing the feelings of those around them.', relatedTerms: ['Modality', 'Polarity'], category: 'astrology' },
  { term: 'Whole Sign Houses', slug: 'whole-sign-houses', definition: 'The oldest house system in Western astrology, where each house corresponds exactly to one complete zodiac sign. The sign of the Ascendant becomes the entire 1st house, the next sign becomes the 2nd house, and so on. Whole Sign Houses has seen a major revival in modern practice due to its simplicity and strong ties to Hellenistic tradition.', relatedTerms: ['Houses', 'Ascendant', 'Birth Chart'], category: 'astrology' },
  // === Y ===
  { term: 'Yod', slug: 'yod', definition: 'A rare aspect pattern formed by two planets in sextile with both making quincunxes to a third planet, creating a narrow triangle. Called the "Finger of God," the Yod produces a persistent, fated quality — a sense that you are being pointed toward a specific purpose or lesson that is difficult to ignore and requires ongoing adjustment.', relatedTerms: ['Quincunx', 'Sextile', 'Aspect'], category: 'astrology' },
  // === Z ===
  { term: 'Zenith', slug: 'zenith', definition: 'The point directly overhead in the sky, opposite the nadir. While commonly confused with the Midheaven (MC), the zenith and MC are technically different points that happen to be close in most charts. The zenith represents the highest point of visibility and, symbolically, the peak of one\'s public presence and achievement.', relatedTerms: ['Nadir', 'MC (Midheaven)'], category: 'astrology' },
  { term: 'Zodiac', slug: 'zodiac', definition: 'The belt of sky divided into twelve equal 30-degree segments, each named after a constellation: Aries, Taurus, Gemini, Cancer, Leo, Virgo, Libra, Scorpio, Sagittarius, Capricorn, Aquarius, and Pisces. The zodiac is the framework upon which all Western astrology is built, providing the signs through which planets express their energies.', relatedTerms: ['Sun Sign', 'Birth Chart'], category: 'astrology' },
  // === Additional terms to reach 150+ ===
  { term: 'Composite Chart', slug: 'composite-chart', definition: 'A relationship chart created by finding the midpoint between each pair of planets in two people\'s birth charts. Unlike synastry, which compares two charts, a composite chart creates a single new chart representing the relationship as its own entity. It reveals the purpose, dynamics, and destiny of the partnership itself.', relatedTerms: ['Synastry', 'Birth Chart'], category: 'astrology' },
  { term: 'Decanate', slug: 'decanate', definition: 'Another term for decan — the division of each zodiac sign into three 10-degree sections. Each decanate adds a secondary planetary influence to the sign, creating subtle differences between people born under the same sign but in different decans. Understanding decanates explains why early Aries feels different from late Aries.', relatedTerms: ['Decan', 'Zodiac'], category: 'astrology' },
  { term: 'Direct', slug: 'direct', definition: 'When a planet resumes its normal forward motion through the zodiac after a retrograde period. A planet going direct brings renewed momentum, clarity, and forward progress in the areas it governs. The day a planet stations direct is often experienced as a turning point or a sense of things finally moving again.', relatedTerms: ['Retrograde', 'Station'], category: 'astrology' },
  { term: 'Dispositor', slug: 'dispositor', definition: 'The ruler of the sign a planet occupies. If your Moon is in Capricorn, Saturn (ruler of Capricorn) is the dispositor of your Moon. Following the chain of dispositors in a chart reveals how planetary energies connect and which planet holds ultimate authority — the final dispositor.', relatedTerms: ['Ruler', 'Domicile'], category: 'astrology' },
  { term: 'Diurnal', slug: 'diurnal', definition: 'Relating to the daytime. A diurnal chart is one where the Sun is above the horizon (the person was born during the day). Diurnal planets — the Sun, Jupiter, and Saturn — perform better in day charts. Understanding whether your chart is diurnal or nocturnal helps assess planetary strength through the concept of sect.', relatedTerms: ['Sect', 'Nocturnal'], category: 'astrology' },
  { term: 'Dragon\'s Head', slug: 'dragons-head', definition: 'An ancient term for the North Node of the Moon. In Vedic astrology, it is called Rahu. The Dragon\'s Head represents appetite, desire, and the direction of karmic growth. Its sign and house placement show where you are meant to expand and develop new capabilities.', relatedTerms: ['North Node', 'South Node', 'Dragon\'s Tail'], category: 'astrology' },
  { term: 'Dragon\'s Tail', slug: 'dragons-tail', definition: 'An ancient term for the South Node of the Moon. In Vedic astrology, it is called Ketu. The Dragon\'s Tail represents release, past mastery, and what you are meant to let go of. Its placement shows karmic patterns and innate skills that can become crutches if relied upon too heavily.', relatedTerms: ['South Node', 'North Node', 'Dragon\'s Head'], category: 'astrology' },
  { term: 'Ecliptic', slug: 'ecliptic', definition: 'The apparent path of the Sun across the sky over the course of a year, which defines the plane of Earth\'s orbit. The zodiac belt is centered on the ecliptic, and planetary positions are measured along it. Eclipses occur when the Moon crosses the ecliptic at a new or full moon.', relatedTerms: ['Zodiac', 'Eclipse'], category: 'astrology' },
  { term: 'Element', slug: 'element', definition: 'One of the four fundamental energies in astrology and tarot: Fire (passion, action), Earth (material, practical), Air (intellectual, social), and Water (emotional, intuitive). Each zodiac sign belongs to one element, and each tarot suit corresponds to one element. Balance among the elements is a sign of a well-rounded personality.', relatedTerms: ['Fire Signs', 'Earth Signs', 'Air Signs', 'Water Signs'], category: 'general' },
  { term: 'Equinox', slug: 'equinox', definition: 'The two days per year when the Sun crosses the celestial equator, making day and night approximately equal in length. The vernal (spring) equinox marks the Sun\'s entry into Aries and the start of the astrological new year. The autumnal equinox marks its entry into Libra.', relatedTerms: ['Ingress', 'Solstice', 'Zodiac'], category: 'astrology' },
  { term: 'Essential Dignity', slug: 'essential-dignity', definition: 'A planet\'s inherent strength based on its zodiac sign placement, as distinguished from accidental dignity (based on house placement). The five levels of essential dignity are domicile, exaltation, triplicity, term, and face. A planet with strong essential dignity can express its nature fully and effectively.', relatedTerms: ['Dignities', 'Domicile', 'Exaltation'], category: 'astrology' },
  { term: 'Fixed Star', slug: 'fixed-star', definition: 'A star whose position in the zodiac changes very slowly (about 1 degree every 72 years). Certain fixed stars — like Regulus, Algol, Spica, and Sirius — have been studied by astrologers for millennia and carry specific meanings when conjunct planets or points in a birth chart.', relatedTerms: ['Birth Chart', 'Conjunction'], category: 'astrology' },
  { term: 'Full Moon', slug: 'full-moon', definition: 'The lunar phase when the Moon is directly opposite the Sun, fully illuminated from Earth\'s perspective. Full moons bring things to completion, illuminate hidden truths, and heighten emotions. In astrology, the full moon activates the axis of the signs it falls in, and in tarot, it is an ideal time for release and clarity readings.', relatedTerms: ['Lunation', 'Moon Phases', 'Eclipse'], category: 'general' },
  { term: 'Galactic Center', slug: 'galactic-center', definition: 'The rotational center of the Milky Way galaxy, located at approximately 27 degrees Sagittarius. Planets or chart points conjunct the Galactic Center are said to act as conduits for universal wisdom, higher knowledge, and cosmic downloads. People with strong Galactic Center contacts often feel drawn to teaching, publishing, or broadcasting.', relatedTerms: ['Fixed Star', 'Conjunction'], category: 'astrology' },
  { term: 'Hellenistic Astrology', slug: 'hellenistic-astrology', definition: 'The system of astrology practiced in the Greco-Roman world from approximately the 2nd century BCE through the 7th century CE. Hellenistic astrology is the root of Western astrology, introducing concepts like whole sign houses, sect, lots, and time lord techniques. It has seen a significant revival in the 21st century.', relatedTerms: ['Whole Sign Houses', 'Sect', 'Lot of Fortune'], category: 'astrology' },
  { term: 'Horoscope', slug: 'horoscope', definition: 'Technically, a horoscope is an astrological chart cast for a specific moment in time. In popular usage, it refers to the daily, weekly, or monthly astrological forecasts published in media, written for each Sun sign. While Sun sign horoscopes are simplified, they are based on real transits affecting each sign\'s solar house system.', relatedTerms: ['Sun Sign', 'Transit', 'Birth Chart'], category: 'astrology' },
  { term: 'Inconjunct', slug: 'inconjunct', definition: 'Another name for the quincunx aspect of 150 degrees. The inconjunct connects two planets in signs with nothing in common — no shared element, modality, or polarity. This produces a persistent, low-grade tension and the need for ongoing adjustment and creative problem-solving.', relatedTerms: ['Quincunx', 'Aspect'], category: 'astrology' },
  { term: 'Karmic Astrology', slug: 'karmic-astrology', definition: 'An approach to astrology that interprets the chart through the lens of past lives, karma, and soul evolution. Key indicators include the Nodes of the Moon, Saturn placements, and the 12th house. Karmic astrology explores why you chose this incarnation and what spiritual lessons you are here to learn.', relatedTerms: ['North Node', 'South Node', 'Saturn'], category: 'astrology' },
  { term: 'Lenormand', slug: 'lenormand', definition: 'A 36-card divination system named after Marie Anne Lenormand, a famous 19th-century French fortune teller. Lenormand cards are read differently from tarot — they use combinations and tableaus rather than individual card interpretation. Each card depicts a simple symbol like a Ship, Tree, or Fox with specific predictive meanings.', relatedTerms: ['Divination', 'Reading'], category: 'general' },
  { term: 'Luminaries', slug: 'luminaries', definition: 'The Sun and Moon — the two brightest celestial bodies as seen from Earth. In astrology, the luminaries are the most important placements, representing the core self (Sun) and emotional nature (Moon). They illuminate the chart and give it vitality. Without the luminaries, a chart has no center of gravity.', relatedTerms: ['Sun', 'Moon', 'Birth Chart'], category: 'astrology' },
  { term: 'Midpoint', slug: 'midpoint', definition: 'The exact halfway point between two planets or points in a birth chart. Midpoints reveal hidden connections and blend the energies of both bodies. The Sun/Moon midpoint is especially important — it represents the integration of your conscious and unconscious selves and is a key point in relationship astrology.', relatedTerms: ['Composite Chart', 'Birth Chart'], category: 'astrology' },
  { term: 'New Moon', slug: 'new-moon', definition: 'The lunar phase when the Moon is conjunct the Sun and invisible from Earth, marking the start of a new lunar cycle. New moons are optimal for setting intentions, beginning new projects, and planting seeds for the future. In tarot, new moon readings focus on intentions and what is ready to be initiated.', relatedTerms: ['Lunation', 'Moon Phases', 'Conjunction'], category: 'general' },
  { term: 'Nocturnal', slug: 'nocturnal', definition: 'Relating to nighttime. A nocturnal chart is one where the Sun is below the horizon (the person was born at night). Nocturnal planets — the Moon, Venus, and Mars — perform better in night charts. Knowing whether your chart is nocturnal changes how benefic and malefic planets function for you.', relatedTerms: ['Sect', 'Diurnal'], category: 'astrology' },
  { term: 'Oracle Cards', slug: 'oracle-cards', definition: 'Divination decks that are not bound by the traditional tarot structure of 78 cards in four suits plus Major Arcana. Oracle decks can have any number of cards with any theme — angels, animals, crystals, affirmations, or original artwork. They are typically more free-form and intuitive than tarot.', relatedTerms: ['Divination', 'Reading', 'Tarot Spread'], category: 'general' },
  { term: 'Peregrine', slug: 'peregrine', definition: 'A planet with no essential dignity in its current sign — not in domicile, exaltation, triplicity, term, or face. A peregrine planet is like a wanderer without a home, drifting without purpose. In horary astrology, a peregrine planet can indicate a thief, while in natal charts it may indicate a quality that has not yet found its proper expression.', relatedTerms: ['Dignities', 'Essential Dignity'], category: 'astrology' },
  { term: 'Personal Planets', slug: 'personal-planets', definition: 'The Sun, Moon, Mercury, Venus, and Mars — the fast-moving planets whose influence is most felt in daily life and personal character. Personal planets define how you think (Mercury), love (Venus), act (Mars), feel (Moon), and express your core self (Sun). They move quickly through the zodiac, creating individual differences.', relatedTerms: ['Outer Planets', 'Birth Chart'], category: 'astrology' },
  { term: 'Profection', slug: 'profection', definition: 'An ancient timing technique that assigns each year of life to a house, cycling through the twelve houses repeatedly. Your first year activates the 1st house, your second year the 2nd house, and so on. At age 12, you return to the 1st house for the second cycle. The activated house and its ruler set the theme for that year.', relatedTerms: ['Houses', 'Ruler', 'Hellenistic Astrology'], category: 'astrology' },
  { term: 'Querent\'s Significator', slug: 'querents-significator', definition: 'In horary astrology, the planet that represents the person asking the question, determined by the ruler of the 1st house. The significator\'s condition — its dignity, aspects, and house placement — describes the querent\'s situation and capacity to achieve what they are asking about.', relatedTerms: ['Horary Astrology', 'Querent', 'Significator'], category: 'astrology' },
  { term: 'Rectification', slug: 'rectification', definition: 'The astrological technique of determining an unknown or uncertain birth time by working backward from known life events. By checking which birth time produces a chart consistent with the person\'s actual experiences, relationships, and character, an astrologer can narrow down the birth time, sometimes to the minute.', relatedTerms: ['Birth Chart', 'Ascendant'], category: 'astrology' },
  { term: 'Rider-Waite-Smith', slug: 'rider-waite-smith', definition: 'The most influential tarot deck in the English-speaking world, published in 1909 with art by Pamela Colman Smith and direction from Arthur Edward Waite. It was the first widely available deck to include illustrated scenes on the Minor Arcana pip cards, making it dramatically easier for beginners to learn tarot through visual storytelling.', relatedTerms: ['Major Arcana', 'Minor Arcana', 'Pip Cards'], category: 'tarot' },
  { term: 'Sabian Symbols', slug: 'sabian-symbols', definition: 'A set of 360 symbolic images — one for each degree of the zodiac — channeled by psychic Elsie Wheeler in 1925 and later refined by astrologer Marc Edmund Jones. Each symbol adds a layer of meaning to any planet or point that falls on that degree. They are used for meditation, prediction, and adding nuance to chart interpretation.', relatedTerms: ['Zodiac', 'Birth Chart'], category: 'astrology' },
  { term: 'Sesquiquadrate', slug: 'sesquiquadrate', definition: 'A minor aspect of 135 degrees between two planets, combining the energies of a square and a semi-square. The sesquiquadrate creates persistent agitation and the drive to resolve internal conflict through external action. Like the semi-square, it motivates change through ongoing low-level friction.', relatedTerms: ['Aspect', 'Square', 'Semi-Square'], category: 'astrology' },
  { term: 'Solstice', slug: 'solstice', definition: 'The two days per year when the Sun reaches its maximum declination north or south of the celestial equator, creating the longest and shortest days. The summer solstice (Sun enters Cancer) and winter solstice (Sun enters Capricorn) are powerful turning points in both the astronomical and astrological year.', relatedTerms: ['Equinox', 'Ingress'], category: 'astrology' },
  { term: 'Station', slug: 'station', definition: 'The apparent moment when a planet stops its motion before changing direction — either from direct to retrograde (retrograde station) or from retrograde to direct (direct station). A planet at its station is at peak intensity, and its themes dominate the surrounding days. Station days are felt powerfully in transit readings.', relatedTerms: ['Retrograde', 'Direct', 'Transit'], category: 'astrology' },
  { term: 'Stellium', slug: 'stellium-2', definition: 'Three or more planets clustered in the same sign or house, concentrating energy intensely in that area of the chart. A stellium makes the themes of its sign and house dominant in the person\'s life, for better or worse. Managing a stellium requires learning to channel its concentrated power without becoming one-dimensional.', relatedTerms: ['Conjunction', 'Birth Chart'], category: 'astrology' },
  { term: 'Thema Mundi', slug: 'thema-mundi', definition: 'The mythical "birth chart of the world" used in Hellenistic astrology as a teaching tool. It places Cancer on the Ascendant with each planet in its domicile, illustrating the fundamental relationships between planets and signs. The Thema Mundi is not a real chart but a conceptual model for understanding planetary rulership.', relatedTerms: ['Hellenistic Astrology', 'Domicile', 'Ruler'], category: 'astrology' },
  { term: 'Time Lord', slug: 'time-lord', definition: 'In Hellenistic astrology, a planet that governs a specific period of your life according to a timing technique such as zodiacal releasing, annual profections, or decennials. The Time Lord\'s condition in your birth chart shapes the quality and themes of its activated period, explaining why certain years feel dramatically different from others.', relatedTerms: ['Profection', 'Hellenistic Astrology'], category: 'astrology' },
  { term: 'Triplicity', slug: 'triplicity', definition: 'A group of three zodiac signs sharing the same element (Fire, Earth, Air, or Water). Each triplicity has day and night rulers who gain additional dignity when they rule the triplicity in a chart of the matching sect. Triplicity lords are used in traditional astrology to assess a planet\'s secondary strength.', relatedTerms: ['Element', 'Sect', 'Dignities'], category: 'astrology' },
  { term: 'Vedic Astrology', slug: 'vedic-astrology', definition: 'The traditional Hindu system of astrology, also known as Jyotish, which uses the sidereal zodiac (based on actual star positions) rather than the tropical zodiac used in Western astrology. Vedic astrology has a highly developed system of planetary periods (dashas), divisional charts, and remedial measures.', relatedTerms: ['Zodiac', 'Birth Chart'], category: 'astrology' },
  { term: 'Void', slug: 'void', definition: 'Short for Void of Course — the period when the Moon makes no more major aspects before leaving its current sign. The void Moon is traditionally considered an inauspicious time for initiating new activities. However, it can be excellent for routine tasks, meditation, rest, and activities that do not need a specific outcome.', relatedTerms: ['Void of Course', 'Moon', 'Aspect'], category: 'astrology' },
  { term: 'Zodiacal Releasing', slug: 'zodiacal-releasing', definition: 'A Hellenistic time-lord technique that divides life into periods ruled by different zodiac signs, starting from the Lot of Spirit or Lot of Fortune. Zodiacal Releasing identifies peak periods of career achievement, creative output, and personal turning points. It has gained popularity for its remarkable accuracy in timing major life events.', relatedTerms: ['Hellenistic Astrology', 'Time Lord', 'Lot of Fortune'], category: 'astrology' },
]

